import React, { useEffect, useMemo, useState } from 'react';
import { Link } from 'react-router-dom';
import './Hero.css';

const statItems = [
  { label: '오늘의 체크인', value: '1.2만+', tone: 'purple' },
  { label: '누적 대화 세션', value: '8.4만+', tone: 'blue' },
  { label: '감정 리포트 생성', value: '3.1만+', tone: 'mint' },
];

function SendIcon() {
  return (
    <svg viewBox="0 0 24 24" aria-hidden="true">
      <path
        d="M4 11.5L19 4l-3.8 16-4.1-5-4.9-1.1L4 11.5z"
        fill="none"
        stroke="currentColor"
        strokeWidth="1.8"
        strokeLinejoin="round"
      />
    </svg>
  );
}

export default function Hero() {
  const [scrollRatio, setScrollRatio] = useState(0);
  const [scrollState, setScrollState] = useState('idle');
  const [demoInput, setDemoInput] = useState('');

  useEffect(() => {
    const onScroll = () => {
      const y = window.scrollY || 0;
      const ratio = Math.min(y / 520, 1);
      setScrollRatio(ratio);

      if (y < 80) setScrollState('idle');
      else if (y < 320) setScrollState('wave');
      else setScrollState('react');
    };

    onScroll();
    window.addEventListener('scroll', onScroll, { passive: true });
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  const heroDemo = useMemo(() => {
    if (scrollState === 'wave') {
      return {
        persona: '하루',
        mode: '반갑게 먼저 인사하는 대화형',
        topic: 'Welcome',
        bubble:
          '앗, 스크롤하고 있네요. 반가워요. 오늘 기분이나 지금 떠오르는 생각을 짧게라도 말해볼래요?',
        options: ['오늘 조금 피곤해요', '그냥 편하게 얘기하고 싶어요'],
        placeholder: '지금 마음을 한 줄로 적어보세요.',
      };
    }

    if (scrollState === 'react') {
      return {
        persona: '하루',
        mode: '조심스럽게 살펴봐주는 공감형',
        topic: 'Mood Check',
        bubble:
          '좋아요. 아래 기능들도 둘러보면 더 잘 맞는 흐름을 찾을 수 있어요. 지금 가장 가까운 감정은 어떤 쪽인가요?',
        options: ['생각이 많아요', '조금 위로받고 싶어요'],
        placeholder: '지금 떠오르는 감정을 적어보세요.',
      };
    }

    return {
      persona: '하루',
      mode: '차분하고 따뜻한 공감형',
      topic: 'Work Stress',
      bubble:
        '오늘도 오래 버텼네요. 많이 애쓴 하루였어요. 지금 제일 무거운 감정은 어떤 건가요?',
      options: ['피곤함이 커요', '마음이 답답해요'],
      placeholder: '하루에게 지금 기분을 말해보세요.',
    };
  }, [scrollState]);

  return (
    <section className="cutehero-section" style={{ '--hero-scroll': scrollRatio }}>
      <div className="cutehero-bg cutehero-bg--one" />
      <div className="cutehero-bg cutehero-bg--two" />
      <div className="cutehero-bg cutehero-bg--three" />

      <div className="cutehero-container">
        <div className="cutehero-grid">
          <div className="cutehero-copy">
            <span className="cutehero-kicker">Virtual Care Companion</span>

            <h1>
              오늘의 마음을
              <br />
              <strong>조금 더 다정하고 귀엽게 돌봐주는 AI 캐릭터</strong>
            </h1>

            <p>
              단순한 텍스트 챗봇이 아니라, 화면 안에 살아 있는 것처럼 반응하는 버추얼 캐릭터와
              함께 감정 체크인, 대화, 일기, 리포트를 자연스럽게 이어갈 수 있어요.
            </p>

            <div className="cutehero-actions">
              <Link to="/chat" className="cutehero-btn cutehero-btn--primary">
                캐릭터와 대화 시작하기
              </Link>
              <Link to="/signup" className="cutehero-btn cutehero-btn--ghost">
                무료로 시작하기
              </Link>
            </div>

            <div className="cutehero-stats">
              {statItems.map((item) => (
                <div
                  key={item.label}
                  className={`cutehero-stat-card cutehero-stat-card--${item.tone}`}
                >
                  <span>{item.label}</span>
                  <strong>{item.value}</strong>
                </div>
              ))}
            </div>
          </div>

          <div className={`cutehero-visual cutehero-visual--${scrollState}`}>
            <div className="cutehero-visual-card">
              <div className="cutehero-demo-shell">
                <div className="cutehero-demo-top">
                  <div className="cutehero-demo-profile">
                    <div className="cutehero-demo-avatar-mini">하</div>
                    <div className="cutehero-demo-profile__text">
                      <strong>{heroDemo.persona}</strong>
                      <span>{heroDemo.mode}</span>
                    </div>
                  </div>

                  <span className="cutehero-demo-topic">{heroDemo.topic}</span>
                </div>

                <div className="cutehero-demo-stage">
                  <div className="cutehero-demo-stage__orb cutehero-demo-stage__orb--one" />
                  <div className="cutehero-demo-stage__orb cutehero-demo-stage__orb--two" />
                  <div className="cutehero-demo-stage__orb cutehero-demo-stage__orb--three" />

                  <div className={`cutehero-character cutehero-character--${scrollState}`}>
                    <div className="cutehero-character__halo" />

                    <div className="cutehero-character__head">
                      <span className="eye left" />
                      <span className="eye right" />
                      <span className={`mouth mood-${scrollState}`} />
                      <span className="cheek left" />
                      <span className="cheek right" />
                    </div>

                    <div className="cutehero-character__body">
                      <span className="core" />
                    </div>

                    <div className="cutehero-character__arm cutehero-character__arm--left" />
                    <div className="cutehero-character__arm cutehero-character__arm--right" />
                  </div>

                  <div className="cutehero-dialogue">
                    <div className="cutehero-dialogue__bubble">
                      <strong>{heroDemo.persona}</strong>
                      <p>{heroDemo.bubble}</p>
                    </div>

                    <div className="cutehero-dialogue__choices">
                      {heroDemo.options.map((option) => (
                        <button
                          key={option}
                          type="button"
                          className="cutehero-choice-chip"
                          onClick={() => setDemoInput(option)}
                        >
                          {option}
                        </button>
                      ))}
                    </div>

                    <div className="cutehero-dialogue__composer">
                      <input
                        type="text"
                        value={demoInput}
                        onChange={(e) => setDemoInput(e.target.value)}
                        placeholder={heroDemo.placeholder}
                      />
                      <button type="button" aria-label="메시지 보내기">
                        <SendIcon />
                      </button>
                    </div>
                  </div>
                </div>

                <div className="cutehero-demo-footer">
                  <span className="cutehero-demo-footer__pill">표정 반응</span>
                  <span className="cutehero-demo-footer__pill">선택지 응답</span>
                  <span className="cutehero-demo-footer__pill">직접 입력 가능</span>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}
